import React, { useEffect, useState } from "react";
import axios from "axios";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
  Tooltip,
  Legend,
} from "chart.js";
import { Bar } from "react-chartjs-2";
import "./Dashboard.css";

ChartJS.register(CategoryScale, LinearScale, BarElement, Title, Tooltip, Legend);

const API_BASE = "http://localhost:7000/api";

function StatCard({ title, value, icon, color }) {
  return (
    <div className="stat-card">
      <div className="icon" style={{ background: color }}>{icon}</div>
      <div className="details">
        <h3>{value}</h3>
        <p>{title}</p>
      </div>
    </div>
  );
}

export default function Dashboard() {
  const [stats, setStats] = useState({ users: 0, brokers: 0, transactions: 0, revenue: 0 });
  const [recent, setRecent] = useState([]);
  const [chartData, setChartData] = useState(null);
  const [loading, setLoading] = useState(true);

  // 🔹 Fetch Dashboard Data
  useEffect(() => {
    const fetchData = async () => {
      try {
        const [statsRes, recentRes, priceRes] = await Promise.all([
          axios.get(`${API_BASE}/admin/stats`),
          axios.get(`${API_BASE}/admin/recent`),
          axios.get(`${API_BASE}/prices`),
        ]);

        setStats(statsRes.data);
        setRecent(recentRes.data);

        const prices = priceRes.data.data || [];
        const grouped = {};

        prices.forEach((item) => {
          const date = new Date(item.createdAt || item.validTill).toLocaleDateString("en-IN");
          if (!grouped[date]) grouped[date] = [];
          grouped[date].push(item);
        });

        const labels = Object.keys(grouped);
        const avgPrice = labels.map((d) =>
          (grouped[d].reduce((sum, i) => sum + (i.basePrice || 0), 0) / grouped[d].length).toFixed(2)
        );
        const avgDiff = labels.map((d) =>
          (grouped[d].reduce((sum, i) => sum + (i.difference || 0), 0) / grouped[d].length).toFixed(2)
        );

        setChartData({
          labels,
          datasets: [
            {
              label: "Avg Base Price (₹)",
              data: avgPrice,
              backgroundColor: "rgba(0, 123, 255, 0.6)",
              borderRadius: 8,
            },
            {
              label: "Avg Difference (₹)",
              data: avgDiff,
              backgroundColor: "rgba(255, 193, 7, 0.6)",
              borderRadius: 8,
            },
          ],
        });
      } catch (err) {
        console.error("Dashboard fetch error:", err);
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, []);

  return (
    <div className="dashboard-container">
      <h2 className="dashboard-title">📊 Admin Dashboard</h2>
      <p className="dashboard-subtitle">Overview of users, revenue & price analytics</p>

      {/* Stats */}
      <div className="stats-grid">
        <StatCard title="Total Users" value={stats.users} icon="👥" color="#e7f1ff" />
        <StatCard title="Total Brokers" value={stats.brokers} icon="💼" color="#fff3cd" />
        <StatCard title="Transactions" value={stats.transactions} icon="🔁" color="#d4edda" />
        <StatCard title="Revenue" value={`₹${stats.revenue}K`} icon="💰" color="#f8d7da" />
      </div>

      {/* Analytics */}
      <div className="analytics-section">
        <h4>📈 Price History Overview</h4>
        {loading ? (
          <div className="loading">Loading graph...</div>
        ) : chartData ? (
          <Bar
            data={chartData}
            options={{
              responsive: true,
              maintainAspectRatio: false,
              plugins: {
                legend: { position: "bottom" },
                tooltip: {
                  callbacks: {
                    label: (context) => `${context.dataset.label}: ₹${context.parsed.y}`,
                  },
                },
              },
              scales: {
                y: {
                  beginAtZero: true,
                  title: { display: true, text: "Price (₹)" },
                },
                x: {
                  title: { display: true, text: "Date" },
                },
              },
            }}
          />
        ) : (
          <div className="no-data">No price records available.</div>
        )}
      </div>

      {/* Recent Activity */}
      <div className="activity-section">
        <div className="activity-header">
          <h4>🕓 Recent Activity</h4>
          <span className="view-all">View All</span>
        </div>
        <table className="activity-table">
          <thead>
            <tr>
              <th>ID</th>
              <th>User</th>
              <th>Action</th>
              <th>Entity</th>
              <th>Date</th>
              <th>Status</th>
            </tr>
          </thead>
          <tbody>
            {recent.length === 0 ? (
              <tr>
                <td colSpan={6} className="no-data">No activity found.</td>
              </tr>
            ) : (
              recent.map((r) => (
                <tr key={r.id}>
                  <td>{r.id}</td>
                  <td>{r.user}</td>
                  <td>{r.action}</td>
                  <td>{r.entity || "—"}</td>
                  <td>{new Date(r.date).toLocaleDateString("en-IN")}</td>
                  <td>
                    <span className={`badge ${r.status === "Success" ? "bg-success" : "bg-danger"}`}>
                      {r.status}
                    </span>
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
}
